// ❌ BAD - assuming reference type assignment creates an independent copy
var order1 = new Address("123 Main St", "New York");
var order2 = order1;
order2.City = "London"; // also changes order1.City - they share the same object

// ✅ GOOD - use records with with-expression for immutable copies
public record class Address(string Street, string City);
var order1 = new Address("123 Main St", "New York");
var order2 = order1 with { City = "London" }; // new object, order1 unchanged
Console.WriteLine(order1.City); // "New York" - unaffected

// ❌ BAD - ArrayList boxes every integer, allocating a heap object per item
var productIds = new ArrayList();
for (int i = 0; i < 10000; i++)
    productIds.Add(i); // 10,000 heap allocations for the integers

// ✅ GOOD - List<int> uses int[] internally, zero boxing
var productIds = new List<int>();
for (int i = 0; i < 10000; i++)
    productIds.Add(i); // no heap allocations for the integers

// ❌ BAD - finalizer delays collection by one GC cycle unnecessarily
public class ReportExporter
{
    private FileStream _file;
    ~ReportExporter() { _file?.Dispose(); } // non-deterministic, expensive
}

// ✅ GOOD - deterministic cleanup with Dispose pattern
public class ReportExporter : IDisposable
{
    private FileStream _file;
    private bool _disposed;
    public void Dispose()
    {
        if (_disposed) return;
        _file?.Dispose();
        _disposed = true;
        GC.SuppressFinalize(this); // removes from finalization queue
    }
}

// ❌ BAD - mutable struct in a list, mutation is silently lost
public struct CartItem { public int Quantity; }
var cart = new List<CartItem> { new CartItem { Quantity = 1 } };
cart[0].Quantity++; // mutates a copy - cart[0].Quantity is still 1

// ✅ GOOD - immutable record struct with explicit replacement
public readonly record struct CartItem(int Quantity);
var cart = new List<CartItem> { new CartItem(1) };
cart[0] = cart[0] with { Quantity = cart[0].Quantity + 1 }; // replaces the item

// ❌ BAD - loads ALL invoices into memory, then filters in C#
var overdueInvoices = _db.Invoices
    .ToList()                          // pulls entire table into memory
    .Where(i => i.DueDate < DateTime.Today && !i.IsPaid);

// ✅ GOOD - WHERE clause is translated to SQL, only matching rows cross the wire
var overdueInvoices = _db.Invoices
    .Where(i => i.DueDate < DateTime.Today && !i.IsPaid)
    .OrderBy(i => i.DueDate)
    .Take(100)
    .ToList(); // materializes only the final 100 rows

// ❌ BAD - connection not disposed if exception is thrown
public async Task<decimal> GetBalanceAsync(int accountId)
{
    var conn = new SqlConnection(_connectionString);
    await conn.OpenAsync();
    // exception here = connection leak
    return await QueryBalanceAsync(conn, accountId);
}

// ✅ GOOD - await using guarantees disposal even on exception
public async Task<decimal> GetBalanceAsync(int accountId)
{
    await using var conn = new SqlConnection(_connectionString);
    await conn.OpenAsync();
    return await QueryBalanceAsync(conn, accountId);
    // conn.DisposeAsync() called automatically here
}

// ❌ BAD - raw IntPtr from P/Invoke has no CLR type safety or lifetime management
[DllImport("kernel32.dll")]
static extern IntPtr GetStdHandle(int nStdHandle);
// IntPtr is just a number - no automatic cleanup, no bounds checking

// ✅ GOOD - SafeHandle wraps the native handle with deterministic cleanup
[DllImport("kernel32.dll", SetLastError = true)]
static extern SafeFileHandle CreateFile(
    string lpFileName, uint dwDesiredAccess, uint dwShareMode,
    IntPtr lpSecurityAttributes, uint dwCreationDisposition,
    uint dwFlagsAndAttributes, IntPtr hTemplateFile);
// SafeFileHandle implements IDisposable - handle closed even on exceptions

// ❌ BAD - O(n^2) allocations building an HTML report with string +=
string htmlReport = "<table>";
foreach (var invoice in invoices)
    htmlReport += $"<tr><td>{invoice.Id}</td><td>{invoice.Amount}</td></tr>";
htmlReport += "</table>";

// ✅ GOOD - StringBuilder builds the HTML in one growable buffer
var sb = new StringBuilder();
sb.Append("<table>");
foreach (var invoice in invoices)
    sb.Append($"<tr><td>{invoice.Id}</td><td>{invoice.Amount}</td></tr>");
sb.Append("</table>");
string htmlReport = sb.ToString(); // one allocation at the end

// ❌ BAD - nullable reference not checked, potential NullReferenceException at runtime
public string GetCustomerEmail(int customerId)
{
    Customer? customer = _repo.FindById(customerId);
    return customer.Email; // NullReferenceException if customer is null
}

// ✅ GOOD - handle null explicitly, let compiler verify the path
public string GetCustomerEmail(int customerId)
{
    Customer? customer = _repo.FindById(customerId);
    if (customer is null)
        throw new ArgumentException($"Customer {customerId} not found");
    return customer.Email; // compiler knows customer is not null here
}

// ❌ BAD - relying on finalizer, file held open until GC decides to run
public class AuditLogger
{
    private FileStream _log;
    ~AuditLogger() { _log?.Close(); } // non-deterministic, blocks other processes
}

// ✅ GOOD - Dispose pattern with finalizer as safety net only
public class AuditLogger : IDisposable
{
    private FileStream _log;
    private bool _disposed;
    protected virtual void Dispose(bool disposing)
    {
        if (_disposed) return;
        if (disposing) _log?.Dispose(); // free managed resources
        _disposed = true;
    }
    public void Dispose() { Dispose(true); GC.SuppressFinalize(this); }
    ~AuditLogger() { Dispose(false); } // safety net only
}

// ❌ BAD - Substring allocates a new string for each date part
string rawDate = "2024-06-15";
int year = int.Parse(rawDate.Substring(0, 4));
int month = int.Parse(rawDate.Substring(5, 2));
int day = int.Parse(rawDate.Substring(8, 2));
// 3 heap allocations

// ✅ GOOD - AsSpan().Slice gives a view, no allocation
ReadOnlySpan<char> rawDate = "2024-06-15".AsSpan();
int year = int.Parse(rawDate.Slice(0, 4));
int month = int.Parse(rawDate.Slice(5, 2));
int day = int.Parse(rawDate.Slice(8, 2));
// 0 heap allocations - Slice is a pointer+length view

// ❌ BAD - Span<T> cannot cross await, this does not compile
async Task ProcessPacketAsync(Span<byte> packet, Stream output)
{
    int written = await output.WriteAsync(packet); // compile error
}

// ✅ GOOD - Memory<T> at the async boundary, Span only for sync work
async Task ProcessPacketAsync(Memory<byte> packet, Stream output)
{
    await output.WriteAsync(packet);              // Memory works across await
    int checksum = ComputeChecksum(packet.Span);  // Span for sync computation
}
int ComputeChecksum(ReadOnlySpan<byte> data)
{
    int sum = 0;
    foreach (var b in data) sum += b;
    return sum;
}

// ❌ BAD - building a 10,000-line audit log with += is O(n^2) copies
string auditLog = "";
foreach (var entry in auditEntries)
    auditLog += $"[{entry.Timestamp:O}] {entry.UserId}: {entry.Action}\n";

// ✅ GOOD - StringBuilder builds the log in one growable buffer
var sb = new StringBuilder(auditEntries.Count * 80);
foreach (var entry in auditEntries)
    sb.Append('[').Append(entry.Timestamp.ToString("O"))
      .Append("] ").Append(entry.UserId)
      .Append(": ").AppendLine(entry.Action);
string auditLog = sb.ToString();

// ❌ BAD - enabling Server GC on a 1-core 256MB container wastes memory
// runtimeconfig.json (wrong for a memory-constrained single-core pod)
{
  "configProperties": {
    "System.GC.Server": true
  }
}
// reserves most available RAM for per-core GC heap segments

// ✅ GOOD - match GC mode to the deployment target
// For a multi-core API server (8+ cores, 4+ GB RAM)
{
  "configProperties": {
    "System.GC.Server": true,
    "System.GC.Concurrent": true
  }
}
// For a sidecar or single-core container: omit or set Server to false
